{ pkgs, ... }:
{
  home.packages = [ pkgs.tmuxinator ];

  home.file.".config/tmux/session-logger.sh" = {
    executable = true;
    text = ''
      #!/usr/bin/env sh
      mkdir -p ~/.local/share/tmux
      LOG=~/.local/share/tmux/session-history.log
      while true; do
        sleep 30
        tmux list-windows -a \
          -F "$(date +%Y-%m-%dT%H:%M:%S)  #{session_name}:#{window_index}  #{window_name}  #{pane_current_path}" \
          >> "$LOG" 2>/dev/null
        # Trim to last 10 000 lines to cap file size
        if [ "$(wc -l < "$LOG")" -gt 10000 ]; then
          tail -n 10000 "$LOG" > "$LOG.tmp" && mv "$LOG.tmp" "$LOG"
        fi
      done
    '';
  };

  programs.tmux = {
    enable = true;
    extraConfig = builtins.readFile ./tmux.conf;
    plugins = with pkgs.tmuxPlugins; [
      sensible
      yank
      tmux-fzf
      resurrect
      continuum
      tmux-sessionx
      tmux-thumbs
      open
      extrakto
    ];
  };
}

